// // (1) load: Shifts right by one bit instead of loading. Synchronous active high.
// (2) shift: Loads shift register with data[15:0].
// (3) q: The contents of the shift register.
module top_module(
	input clk,
	input load,
	input shift,
	input [15:0] data,
	output reg [15:0] q);always @(posedge clk) begin
		if (load)
			q <= data;
		else if (shift)
			q <= {1'b0, q[15:1]};
	end
endmodule

